class ExpertSystem:
    """简化的专家系统推理引擎"""
    def __init__(self):
        self.rules = []  # (条件列表, 结论)
        self.facts = set()

    def add_rule(self, conditions, conclusion):
        self.rules.append((conditions, conclusion))

    def forward_chain(self):
        """正向链：从已知事实推导新结论"""
        changed = True
        while changed:
            changed = False
            for conditions, conclusion in self.rules:
                if all(c in self.facts for c in conditions):
                    if conclusion not in self.facts:
                        self.facts.add(conclusion)
                        changed = True
                        print(f"推导: {conclusion}")
        return self.facts

    def backward_chain(self, goal):
        """反向链：从目标出发寻找证据"""
        if goal in self.facts:
            return True
        for conditions, conclusion in self.rules:
            if conclusion == goal:
                if all(self.backward_chain(c) for c in conditions):
                    self.facts.add(goal)
                    return True
        return False

